import { createRouter, createWebHistory } from 'vue-router'
import HomePage from '../App.vue'
import StatsPage from '../views/StatsPage.vue'

const routes = [
  {
    path: '/',
    name: 'Home',
    component: HomePage
  },
  {
    path: '/stats',
    name: 'Stats',
    component: StatsPage
  }
]

const router = createRouter({
  history: createWebHistory(),
  routes
})

export default router
